// Load provider configuration
const bookingData = items[0].json;

// This would normally load from your config file
// For now, we'll set it in workflow settings
const providers = [
  {
    id: 'provider_1',
    priority: 1,
    name: $node['Set Providers Config'].json.provider1_name,
    lineId: $node['Set Providers Config'].json.provider1_line_id,
    email: $node['Set Providers Config'].json.provider1_email,
    active: true
  },
  {
    id: 'provider_2',
    priority: 2,
    name: $node['Set Providers Config'].json.provider2_name,
    lineId: $node['Set Providers Config'].json.provider2_line_id,
    email: $node['Set Providers Config'].json.provider2_email,
    active: true
  },
  {
    id: 'provider_3',
    priority: 3,
    name: $node['Set Providers Config'].json.provider3_name,
    lineId: $node['Set Providers Config'].json.provider3_line_id,
    email: $node['Set Providers Config'].json.provider3_email,
    active: true
  }
];

// Sort by priority and get active providers
const activeProviders = providers
  .filter(p => p.active)
  .sort((a, b) => a.priority - b.priority);

return [{
  json: {
    ...bookingData,
    providers: activeProviders,
    currentProviderIndex: 0,
    currentProvider: activeProviders[0]
  }
}];

