parameters.functionCode:
// Parse provider response from LINE message
const message = items[0].json.events[0].message.text.toUpperCase();
const bookingId = items[0].json.events[0].message.text.match(/BK\d+/)?.[0];

// Retrieve booking data from storage (you'd use a database in production)
// For this example, we'll assume it's passed through
const bookingData = $input.first().json;

let response = {
  bookingId: bookingId,
  providerId: items[0].json.events[0].source.userId,
  messageText: message,
  timestamp: new Date().toISOString()
};

if (message.includes('CONFIRM')) {
  // Parse confirmation details
  const timeMatch = message.match(/(\d{1,2}:\d{2}\s?(?:AM|PM))/i);
  const locationMatch = message.split(/CONFIRM/i)[1]?.split(/,(.+)/)?.[1]?.trim();

  response.status = 'confirmed';
  response.pickupTime = timeMatch ? timeMatch[0] : 'TBD';
  response.pickupLocation = locationMatch || 'TBD';
} else if (message.includes('CANCEL') || message.includes('FULLY BOOKED')) {
  response.status = 'rejected';
  response.reason = 'Fully booked';
} else {
  response.status = 'unclear';
}

return [{ json: { ...bookingData, providerResponse: response } }];

// Check if there are more providers to try
const data = items[0].json;
const currentIndex = data.currentProviderIndex;
const providers = data.providers;

if (currentIndex + 1 < providers.length) {
  // Try next provider
  return [{
    json: {
      ...data,
      currentProviderIndex: currentIndex + 1,
      currentProvider: providers[currentIndex + 1],
      tryNextProvider: true
    }
  }];
} else {
  // All providers fully booked
  return [{
    json: {
      ...data,
      tryNextProvider: false,
      allProvidersBooked: true
    }
  }];
}
